mapper.select:
select TPWT.ID, TBT.TRUST_NO, TBT.iD trust_id, TMP_TBTC.cargo_info_no, TMP_TBTC.cargo_name, TMP_TBTC.CARGO_OWNER_NAME, TMP_TBTC.PACKAGE_NAME, TPWT.PROCESS_NAME, TPWP.PROCESS_CODE, TPWP.PLAN_TYPE, TRUST_SHIP."shipvoyageLabel" "shipvoyageLabel", TPWT.WORK_PLAN_ID, TBT.COMPANY_NAME, TBT.COMPANY_ID, TBT.port_code,
TPWT.TICKET_TYPE, TRUST_SHIP.SCN, TRUST_SHIP.LOAD_UNLOAD, decode(TPWT.TICKET_TYPE,'1','调度签票','2','库场签票') TICKET_TYPE_LABEL, tmp_ticket_detail.ALLOT_TYPE, decode(tmp_ticket_detail.ALLOT_TYPE,'2','机械分配','3','人员分配','未分配') allot_type_label from T_PRD_WORK_TICKET TPWT left join T_PRD_WORK_PLAN TPWP on TPWT.WORK_PLAN_ID = TPWP.ID left join T_BUS_TRUST TBT on TPWP.TRUST_ID = TBT.ID left join ( select TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.CARGO_INFO_NO), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) cargo_info_no, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.CARGO_NAME), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) cargo_name, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.CARGO_CODE), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) cargo_code, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.CARGO_OWNER_NAME), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) CARGO_OWNER_NAME, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.CARGO_OWNER_ID), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) CARGO_OWNER_ID, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.PACKING_CODE), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) PACKAGE_CODE, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCI.PACKING_NAME), ',') WITHIN GROUP ( ORDER BY TBCI.CARGO_INFO_NO ), '([^,]+)(,\1)+', '\1')) PACKAGE_NAME, TBTC.TRUST_ID from T_BUS_TRUST_CARGO TBTC left join T_BUS_CARGO_INFO TBCI on TBTC.CARGO_INFO_ID = TBCI.ID group by TBTC.TRUST_ID) TMP_TBTC on TMP_TBTC.TRUST_ID = TBT.ID left join (select TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCS.SHIP_NAME||'_'||TBCS.VOYAGE), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) "shipvoyageLabel" ,TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCS.SHIP_VOYAGE_ITEM_ID), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) SHIP_VOYAGE_ITEM_ID, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TDS.SCN), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) SCN, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TDS.LOAD_UNLOAD), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) LOAD_UNLOAD, TBCS.TRUST_ID from T_BUS_CARGO_SHIP TBCS left join T_DIS_SHIPVOYAGE TDS on TBCS.SHIP_VOYAGE_ID = TDS.ID group by TRUST_ID) TRUST_SHIP on TRUST_SHIP.TRUST_ID = TBT.ID left join (select WORK_TICKET_ID,ALLOT_TYPE from T_PRD_WORK_TICKET_DETAIL where ALLOT_TYPE = #{allotType,jdbcType=VARCHAR} group by WORK_TICKET_ID,ALLOT_TYPE) tmp_ticket_detail on tmp_ticket_detail.WORK_TICKET_ID = TPWT.ID
and TPWP.PLAN_TYPE = #{planType,jdbcType=VARCHAR}
and TPWP.WORK_DATE = #{workDate,jdbcType=VARCHAR}
and TPWP.CLASS_CODE = #{classCode,jdbcType=VARCHAR}
AND TBT.PORT_CODE = #{portCode,jdbcType=BIGINT}
and TRUST_SHIP.SHIP_VOYAGE_ITEM_ID like #{shipvoyageItemIdLike}
and TBT.TRUST_NO like #{trustNoLike,jdbcType=VARCHAR}
and TMP_TBTC.CARGO_OWNER_ID like #{cargoOwnerIdLike,jdbcType=VARCHAR}
and TMP_TBTC.cargo_code like #{cargoCodeLike,jdbcType=VARCHAR}
and TMP_TBTC.PACKAGE_CODE like #{packageCodeLike,jdbcType=VARCHAR}

select TBCI.CARGO_NAME||'/'||TBCI.CARGO_OWNER_NAME||'/'||TBCI.CARGO_INFO_NO cargo_info_name, TPWP.id work_plan_id, TBCI.cargo_Info_no, TPWTD.* from T_PRD_WORK_TICKET_DETAIL TPWTD left join T_PRD_WORK_TICKET TPWT on TPWTD.WORK_TICKET_ID = TPWT.ID left join T_PRD_WORK_PLAN TPWP on TPWT.WORK_PLAN_ID =TPWP.ID left join T_BUS_CARGO_INFO TBCI on TBCI.id = TPWTD.CARGO_INFO_ID
and TPWT.ID = #{id,jdbcType=BIGINT}
and TPWT.WORK_PLAN_ID = #{workPlanId,jdbcType=BIGINT}
and TPWTD.ALLOT_TYPE = #{allotType}
and TPWTD.dept_name != '固机队'

select EQUIPMENT_NO, EQUIPMENT_ID , EQUIPMENT_TYPE_CODE, EQUIPMENT_TYPE_NAME, WORK_TICKET_DETAIL_ID
from T_PRD_WORK_TICKET_EQUIPMENT where EXISTS ( select * from (
select #{workTicketId} as TMPID from dual
) a where a.TMPID = WORK_TICKET_DETAIL_ID )

select TPDS.DEPT_ID, TPDS.DEPT_NAME, TPDS.EQUIPMENT_ID, MM.MAC_CODE EQUIPMENT_NO, MM.MAC_NAME EQUIPMENT_NAME, MMT.MAC_TYPE_CODE EQUIPMENT_TYPE_CODE, MMT.ID EQUIPMENT_TYPE_ID, TPDS.NUMBER_COUNT, MMT.mac_type_name EQUIPMENT_TYPE_NAME, TPDS.DEPT_PARENT_ID, TPDS.DEPT_PARENT_NAME, TPDS.SUB_PROCESS_CODE, MWP.PROCESS_NM SUB_PROCESS_NAME, TPDS.WORK_POSITION_CODE, TPDS.WORK_POSITION_NAME, MWP.IS_TALLY_COURSE from T_PRD_DISPATCH_SECONDARY TPDS left join M_MACHINE MM on TPDS.EQUIPMENT_ID = MM.ID left join M_MACHINE_TYPE MMT on TPDS.EQUIPMENT_TYPE_ID = MMT.ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TPDS.SUB_PROCESS_CODE
TPDS.DISPATCH_TYPE = #{dispatchType} and TPDS.WORK_PLAN_ID =#{workPlanId,jdbcType=BIGINT}
and (TPDS.dept_name != '固机队' or not exists( select ID from ( select ID from SYS_DEPT where PARENT_ID != (select id from SYS_DEPT where DEPT_NAME = '固机队' ) ) tmp where TPDS.dept_ID = tmp.id ))

select sd2.id dept_id, TPAU.id, TPAU.user_id from T_PRD_WORK_PLAN TPWP left join T_PRD_ATTENDANCE TPA on ( TPWP.WORK_DATE = TPA.WORK_DATE and TPWP.CLASS_CODE = TPA.CLASS_CODE ) left join T_PRD_ATTENDANCE_USER TPAU on TPA.ID = TPAU.ATTENDANCE_ID left join sys_dept sd on sd.id = TPA.DEPT_ID left join sys_dept sd2 on sd.PARENT_ID = sd2.id where TPWP.id = #{planId,jdbcType=BIGINT} and EXISTS ( select * from (
select #{tmpId} as TMPID from dual
) a where a.TMPID = TPA.dept_id )

select REGEXP_REPLACE(LISTAGG(BERTH_NAME, ',') WITHIN GROUP ( ORDER BY SHIPVOYAGE_ITEM_ID ), '([^,]+)(,\1)+', '\1') BERTH_NAME from T_DIS_SHIP_DYNAMIC where DYNAMIC_TYPE_NAME in ('靠泊' , '移泊') AND EXISTS ( select * from (
select #{tmpId} as TMPID from dual
) a where a.TMPID = SHIPVOYAGE_ITEM_ID )
